import type { SyntaxNodeRef } from '@lezer/common';

import { postSpotErrorMark } from '../../../../decorations/decoration-marks.js';
import type { FilterFieldProps } from '../../../../FilterField.types.js';
import type { ConvertedLezerNode } from '../../../../types/conversion-utils.js';
import type { FilterFieldError } from '../../../../types/filter-field-error.js';
import type { FilterFieldErrorNode } from '../../../../types/tree-nodes.js';
import { getTextFromRange } from '../../../get-text.js';
import { getColoredSearchOperator } from '../../../validation-utils/validation-helper-functions.js';
import { removeEscapeCharacters } from '../../escape-characters.js';

/**
 * Convert a free text node.
 * @internal
 */
export function convertFreeText(
  node: SyntaxNodeRef,
  doc: string,
  parserConfig?: FilterFieldProps['parserConfig'],
): ConvertedLezerNode<Omit<FilterFieldErrorNode, 'value'> & { value: string }> {
  const { from, to } = node;
  const text = getTextFromRange(node, doc);
  const value = removeEscapeCharacters(text);

  const errors: FilterFieldError[] = [];
  const convertedNode: Omit<FilterFieldErrorNode, 'value'> & { value: string } =
    {
      type: 'Error',
      range: {
        from,
        to,
      },
      textValue: text,
      value,
    };

  // eslint-disable-next-line @typescript-eslint/no-deprecated
  if (parserConfig?.searchConversion) {
    errors.push({
      range: { from: to - 1, to },
      message: {
        type: 'incompleteStatementWithEnabledSearchError',
        details: getColoredSearchOperator(),
      },
      decoration: postSpotErrorMark,
    });
  } else {
    errors.push({
      range: { from: to - 1, to },
      message: 'incompleteStatementError',
      decoration: postSpotErrorMark,
    });
  }

  return {
    convertedNode,
    errors,
  };
}
